INSERT INTO bank_product_catalog (product_id, product_name, category, subcategory, short_description, long_description, use_case_tags, indicative_pricing, min_complexity_level, max_complexity_level, eligibility_criteria, prerequisite_products, typical_use_examples, tenor_min_days, tenor_max_days, currency_options, is_pre_approvable, compliance_disclaimer, catalog_version, last_updated_at, source, schema_version, created_at, updated_at) VALUES
  ('octo_biz_current_myr', 'OCTO Biz Current Account (MYR)', 'cash_management', 'current_account', 'Operating account for day-to-day MYR transactions on OCTO Biz.', 'The standard MYR current account on the OCTO Biz SME digital banking platform. Supports unlimited inbound/outbound transfers, standing orders, direct debits, batch payments, and integration with payroll and trade finance products. No minimum balance for active OCTO Biz customers. Statements available via the OCTO Biz app and API. Required as the base account for most other OCTO Biz SME products.', ARRAY['daily_operations','payment_processing','salary_disbursement'], 'No monthly fee. MYR 0.50 per outbound IBG transfer. Inbound transfers free.', 1, 5, 'Registered Malaysian business entity (Sdn Bhd, sole proprietorship, partnership). Valid KYC documentation.', ARRAY[]::TEXT[], 'Daily operating expenses, customer collections, supplier payments, payroll funding source. Ahmad''s primary CIMB MYR account is this product.', NULL, NULL, ARRAY['MYR'], FALSE, 'Account terms and fees subject to CIMB Bank Berhad''s Schedule of Fees. PIDM protected up to RM250,000 per depositor.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('multi_currency_account', 'Multi-Currency Account', 'cash_management', 'multi_currency_account', 'Single account holding multiple foreign currencies (EUR, AUD, USD, GBP, SGD, JPY) for receipt and payment.', 'Allows the SME to hold balances in up to 12 foreign currencies alongside MYR, with separate sub-accounts per currency. Useful for SMEs with recurring foreign payments — receive foreign currency from customers without conversion, hold and pay suppliers in the same currency without round-tripping. FX conversion to/from MYR at prevailing CIMB Treasury rates. No conversion fees on intra-currency transfers.', ARRAY['fx_holding','foreign_payments_smoothing','fx_risk_smoothing','foreign_currency_smoothing'], 'No monthly fee. FX conversion at CIMB Treasury mid + 30-50 bps spread depending on amount and tier.', 2, 5, 'OCTO Biz Current Account holder with FX activity. KYC and FX trading agreement required.', ARRAY['octo_biz_current_myr'], 'SMEs with monthly foreign supplier payments (e.g., wine imports in EUR/AUD) or foreign customer receipts. Reduces FX conversion frequency and helps smooth timing risk by holding a target currency buffer.', NULL, NULL, ARRAY['MYR','EUR','AUD','USD','GBP','SGD','JPY','CNY','HKD','NZD','CHF','CAD'], FALSE, 'Subject to BNM Foreign Exchange Notices. Conversion rates indicative only and may vary at execution. PIDM protection applies to MYR balances only.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('batch_payroll_service', 'Batch Payroll Service', 'cash_management', 'payroll', 'Upload a payroll file and disburse salaries to all employees in one operation.', 'Allows SMEs to upload a CSV or Excel payroll file (employee bank details, amounts, references) and execute all salary disbursements simultaneously. Supports inter-bank transfers via IBG and FPX. Scheduled execution for set payroll dates. Includes electronic payslips delivered to employee emails. Audit trail for reconciliation.', ARRAY['monthly_payroll','batch_payment','salary_disbursement'], 'MYR 0.50 per employee per disbursement. No monthly platform fee.', 2, 5, 'OCTO Biz Current Account with sufficient balance. Active employee count of 5 or more recommended for cost efficiency.', ARRAY['octo_biz_current_myr'], 'SMEs with 10-100 employees running monthly payroll. Ahmad''s Sunrise Trading uses this for monthly disbursement to ~15 staff.', NULL, NULL, ARRAY['MYR'], FALSE, 'Employer responsible for accuracy of payroll data. EPF and SOCSO submissions handled separately by employer. PDPA-compliant data handling.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('flexicash', 'FlexiCash', 'lending', 'revolving_credit', 'Pre-approved revolving credit line you can draw on demand to cover short-term cash needs.', 'A revolving credit facility issued via CIMB''s behavioural credit scoring engine to qualified OCTO Biz SMEs. Funds available immediately on activation — draw any amount up to the approved limit, repay flexibly, redraw as needed. Interest charged only on the outstanding balance. No setup fees. Limit typically between MYR 30K and MYR 500K based on cashflow patterns. Reviewed quarterly. This is the primary product for the FlexiCash hero moment in the v2 demo.', ARRAY['short_term_shortfall','working_capital_topup','emergency_funding','cash_flow_smoothing','payment_smoothing'], '8.5% p.a. (variable, indexed to OPR + 5.5%). No setup fee. No annual fee. Interest charged on daily outstanding balance.', 2, 4, 'Active OCTO Biz customer for 6+ months. Monthly turnover MYR 20K+. No more than 1 missed payment in the last 12 months across all CIMB facilities. Credit score above internal threshold.', ARRAY['octo_biz_current_myr'], 'Bridging a 2-4 week cash dip caused by inventory cycle timing, delayed customer receipts, or unexpected supplier payment requirements. Ahmad''s PoC scenario: cover MYR 65K shortfall over 3 weeks.', NULL, NULL, ARRAY['MYR'], TRUE, 'Variable interest rate may change based on OPR movements. Subject to credit assessment and BNM lending guidelines. Failure to repay may affect credit standing.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('working_capital_facility', 'Working Capital Facility', 'lending', 'revolving_credit', 'Annual renewable credit line secured against business cashflow for ongoing working capital needs.', 'A structured revolving credit facility with a fixed annual limit and quarterly utilisation review. Supports inventory financing, supplier payments, and operating cashflow gaps. Typically secured by personal/corporate guarantee or collateral depending on amount. Lower rate than FlexiCash but requires fuller credit assessment and renewal documentation each year. Limit usually MYR 100K to MYR 5M for SMEs.', ARRAY['short_term_shortfall','working_capital_topup','inventory_financing','payment_smoothing'], '7.2% p.a. (variable, OPR + 4.2%). Setup fee 1% of limit (one-time). Annual review fee MYR 500.', 3, 5, 'Annual turnover MYR 1M+. 2+ years trading history. Audited or compiled financial statements. Director''s personal guarantee typically required.', ARRAY['octo_biz_current_myr'], 'Ahmad''s existing Working Capital Facility limit is MYR 200K with MYR 40K unused. The agent prioritises this for the FlexiCash hero moment because its rate (7.2%) is lower than FlexiCash (8.5%).', 365, 365, ARRAY['MYR'], FALSE, 'Subject to credit approval, BNM lending guidelines, and security documentation. Personal guarantees may apply. Default may result in security enforcement.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('trade_bridging_loan', 'Trade Bridging Loan', 'lending', 'short_term_loan', 'Short-tenor loan tied to a specific trade transaction (import or LC settlement).', 'Provides short-term financing (30-180 days) tied to a specific trade transaction — typically settling an LC, financing an import in transit, or bridging the gap between supplier payment and customer collection. Lower rate than general working capital because the facility is collateralised by the underlying trade documents (bills of lading, invoices, LC reimbursements). Requires submission of trade documents at drawdown.', ARRAY['trade_settlement','lc_settlement','import_bridge'], '6.8% p.a. (fixed for the tenor). 0.5% setup fee per drawdown. Documentary handling fee MYR 100.', 3, 5, 'Existing LC, trust receipt, or documented import/export transaction. Trade documents required at drawdown. Annual turnover MYR 1M+. Typically requires existing trade finance facility with CIMB.', ARRAY['octo_biz_current_myr'], 'Settling an LC payment on bill maturity, bridging payment for imported goods between supplier shipment and customer payment. NOT suitable for general working capital — agent surfaces this option but flags eligibility constraint in the v2 demo loan comparison.', 30, 180, ARRAY['MYR','USD','EUR'], FALSE, 'Documentary support required at drawdown. Subject to BNM trade finance guidelines. Default may trigger document recall and security enforcement.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('sme_term_loan', 'SME Term Loan', 'lending', 'term_loan', 'Fixed-tenor instalment loan for business expansion, asset purchase, or long-term funding.', 'Structured term loan with monthly equal instalments. Used for capital expenditure (machinery, vehicles, premises), business expansion (new branches, hiring), or long-term funding needs. Tenor 1-7 years. Requires business plan submission for amounts above MYR 500K. Secured term loans (against property) typically receive better rates than unsecured.', ARRAY['expansion','asset_purchase','long_term_funding'], '6.5% p.a. (fixed) for secured. 8.0% p.a. unsecured. Setup fee 1% of principal. Early settlement fee 1% of outstanding (after year 1).', 3, 5, 'Business plan for amounts MYR 500K+. 3+ years trading history. Audited financial statements. Collateral or director''s guarantee. Debt-service coverage ratio 1.25x or above.', ARRAY['octo_biz_current_myr'], 'Acquiring a warehouse, financing new branch fit-out, refinancing existing higher-cost debt. NOT suitable for 3-week shortfalls (min tenor 1 year) — agent surfaces this is NOT a match for short-term needs.', 365, 2555, ARRAY['MYR'], FALSE, 'Subject to credit approval and BNM long-term lending guidelines. Collateral valuation required. Default may result in security enforcement.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('business_credit_card', 'Business Credit Card', 'lending', 'credit_card', 'Revolving credit card for travel, corporate expenses, and supplier payments.', 'Standard business credit card with revolving credit. Useful for travel expenses, online supplier payments where card payment is accepted, and corporate entertainment. Statement issued monthly. Interest charged from statement date on unpaid balance. Includes expense management dashboard, individual cards for staff with spending limits, and FX-free transactions on Multi-Currency Account spend.', ARRAY['corporate_expenses','travel'], '18% p.a. on outstanding (variable). Annual fee MYR 250 per card. FX markup 2% on foreign currency card spend (zero if linked to Multi-Currency Account).', 1, 5, 'Active OCTO Biz Current Account. Director credit check. Card limit assessed individually.', ARRAY['octo_biz_current_myr'], 'Travel bookings, online subscriptions, supplier payments under MYR 50K. Generally not suitable for cash flow management due to high interest rate.', NULL, NULL, ARRAY['MYR'], FALSE, 'Late payment incurs late charge of MYR 100 or 1% of outstanding (whichever higher). Subject to BNM credit card guidelines. PIDM protection does not apply.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('spot_fx', 'Spot FX', 'fx', 'spot', 'Immediate foreign exchange conversion at the current market rate (T+2 settlement).', 'On-demand FX conversion service for SMEs. Quote prevailing market mid + a spread depending on amount and customer tier. Settlement T+2. Available for all currencies supported on the Multi-Currency Account. No upfront commitment — execute when needed. Suitable for one-off payments or non-recurring FX needs. Lacks the rate-locking benefit of Forward contracts.', ARRAY['fx_conversion','payment_processing'], 'Treasury mid + 30 bps (Premium tier) to 50 bps (Standard tier). No fixed fee.', 2, 5, 'Multi-Currency Account holder or OCTO Biz Current Account with FX trading agreement.', ARRAY['octo_biz_current_myr'], 'Ad-hoc FX conversions, one-off foreign payments, irregular currency needs. Ahmad''s As-is pattern: calls Maybank RM for spot FX when EUR payment is due. The CFO Agent demo shows replacing this with proactive Forward suggestions.', 0, 2, ARRAY['MYR','EUR','AUD','USD','GBP','SGD','JPY','CNY','HKD','NZD','CHF','CAD'], FALSE, 'Subject to BNM Foreign Exchange Notices. Rates indicative until execution. Settlement T+2. FX risk borne by customer.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('fx_forward_v1', 'FX Forward Contract', 'fx', 'forward', 'Lock today''s rate for delivery on a future date — protects against adverse FX movement.', 'A binding forward contract to exchange a fixed amount of foreign currency on a specified future date at a rate agreed today (spot rate + forward points reflecting interest rate differential and credit spread). Eliminates FX risk for predictable future foreign payments or receipts. Maturity 7-365 days. Common tenors: 30, 60, 90 days. Daily margining not typically required for SME amounts under MYR 1M notional. This is the primary product for the v2 FX Trigger hero moment.', ARRAY['fx_hedging','fx_monthly_payment','predictable_outflow'], 'Spot rate + 15-35 bps forward points depending on tenor (7d=15 bps, 30d=25 bps, 90d=30 bps, 180d=35 bps). No upfront fee for SME tier.', 2, 5, 'Multi-Currency Account or OCTO Biz Current Account. FX trading agreement and ISDA-light documentation signed. Counterparty credit assessment for amounts above MYR 500K notional.', ARRAY['octo_biz_current_myr'], 'Monthly EUR supplier payments where amount and date are known 7+ days ahead. Quarterly AUD payments to overseas distributors. Hedging committed foreign currency receipts. Ahmad''s PoC scenario: lock EUR 8,200 for delivery in 9 days.', 7, 365, ARRAY['EUR','AUD','USD','GBP','SGD','JPY','CNY'], FALSE, 'Binding commitment. Early termination or non-delivery results in mark-to-market settlement at prevailing rate, with potential loss to customer. Subject to BNM FX hedging guidelines.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('fx_limit_order', 'FX Limit Order', 'fx', 'limit_order', 'Auto-execute FX conversion when the market rate reaches your target — like a price alert that buys for you.', 'Place a standing limit order with CIMB Treasury — the order executes automatically when the market mid rate touches your target. No upfront cost. Order good-til-cancelled or up to 30 days. Useful when you have flexibility on timing but want to capture a specific rate. Does not guarantee execution — if the rate never touches your target, no conversion happens.', ARRAY['fx_hedging','rate_target','opportunistic_lock'], 'No upfront cost. On execution, Treasury mid + 25 bps spread. No fees for unfilled orders.', 2, 5, 'Multi-Currency Account or FX trading agreement. Sufficient MYR or foreign currency balance to settle if executed.', ARRAY['octo_biz_current_myr'], 'SME with FX payment due in 2-3 weeks but flexibility on exact timing. Set limit at desired rate, let it execute if market reaches it. Suitable when you can tolerate a few days uncertainty for a potentially better rate.', 1, 30, ARRAY['EUR','AUD','USD','GBP','SGD','JPY','CNY'], FALSE, 'Execution not guaranteed. Order may expire unfilled. Subject to BNM Foreign Exchange Notices.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('fx_hedging_program', 'FX Hedging Program', 'fx', 'hedging_program', 'Structured rolling hedge program for SMEs with large or complex FX exposures (Level 5 only).', 'A dealer-quoted structured hedging arrangement — typically a combination of forwards, options, and FX swaps designed to hedge a multi-month forecasted exposure systematically. Includes mark-to-market reporting and hedge effectiveness analysis. Suitable only for SMEs with treasury function (Level 5 complexity) or annual FX volume above MYR 5M. Requires onboarding by CIMB Treasury sales team.', ARRAY['structured_hedging','large_exposure'], 'Dealer-quoted. Includes embedded spread and structure-specific premium.', 5, 5, 'Annual FX volume MYR 5M+. Treasury function or qualified financial officer. ISDA Master Agreement signed.', ARRAY['octo_biz_current_myr','multi_currency_account'], 'Large importers, exporters, or commodity traders with year-round FX exposure requiring systematic hedge accounting. NOT suitable for Ahmad''s profile (Level 3-4). Agent filters this OUT in the hedging recommendation.', 90, 1095, ARRAY['EUR','AUD','USD','GBP','SGD','JPY','CNY'], FALSE, 'Complex product. Subject to ISDA documentation, BNM Foreign Exchange Notices, and BNM Hedge Accounting guidelines. Mark-to-market losses possible.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('letter_of_credit', 'Letter of Credit (LC)', 'trade_finance', 'lc', 'Bank-issued payment guarantee to a foreign supplier conditional on shipping documents.', 'A documentary credit issued by CIMB on behalf of the SME (applicant) to a foreign supplier (beneficiary), promising payment upon presentation of conforming shipping documents. Used to manage trade payment risk on the buyer side — supplier ships with confidence, buyer pays only when documents conform. CIMB confirms or advises through correspondent banks worldwide. Common in Ahmad''s wine import business with European suppliers.', ARRAY['trade_settlement','import_payment_security','lc_settlement'], 'Issuance commission 0.125% of LC amount per quarter, minimum MYR 500. Amendment fee MYR 200. Discrepancy fee MYR 150. Negotiation/payment fee 0.125% of drawing.', 3, 5, 'Trade finance facility limit approved. Underlying purchase contract. Annual import volume MYR 500K+. Margin deposit may be required (typically 10-30% of LC amount).', ARRAY['octo_biz_current_myr'], 'Importing wine shipment worth EUR 30K from a French producer requiring upfront payment confidence. Ahmad uses LCs for high-value EUR/AUD imports.', 30, 365, ARRAY['MYR','USD','EUR','AUD','GBP','SGD','JPY'], FALSE, 'Subject to UCP 600 (Uniform Customs and Practice for Documentary Credits). Margin deposits may be required. Default on LC reimbursement may trigger trade finance facility recall.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('invoice_financing', 'Invoice Financing', 'trade_finance', 'invoice_financing', 'Get cash today against your outstanding customer invoices instead of waiting 30-90 days.', 'CIMB advances cash against verified customer invoices, typically 80-90% of invoice value, with the remainder (minus fee) paid when the customer settles. Useful for SMEs with payment-term customers (e.g., 30-day net) who want to unlock working capital tied up in receivables. Can be on a single-invoice basis or as a revolving facility against a portfolio of customers.', ARRAY['receivables_funding','cash_flow_smoothing','working_capital_topup'], 'Discount rate 1.0-1.5% per 30 days of expected payment period. Setup fee 0.5% of facility limit (one-time, revolving facility only).', 3, 5, 'Verifiable B2B invoices to creditworthy customers. Annual turnover MYR 1M+. Customer concentration limit applies (no single customer >30% of facility).', ARRAY['octo_biz_current_myr'], 'SME with MYR 100K of outstanding 60-day customer invoices, needs cash now for supplier payment. Receives MYR 85K immediately, MYR 15K minus fees when customers pay.', 30, 180, ARRAY['MYR'], FALSE, 'Customer creditworthiness assessed. Recourse to SME if customer defaults (typical recourse arrangement). Subject to BNM trade finance guidelines.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('trust_receipt_loan', 'Trust Receipt Loan', 'trade_finance', 'trust_receipt', 'Short-term loan to settle an import LC, secured by the underlying goods until sold.', 'When an LC matures and the SME needs time to sell the imported goods before settling the bank, a Trust Receipt Loan provides 30-180 day extension. The bank retains constructive ownership of the goods until repayment. Lower rate than general unsecured short-term loans because of the goods security. Common in cycle of import → sell → repay.', ARRAY['lc_settlement','import_bridge','trade_settlement'], '7.0% p.a. (fixed for tenor). Handling fee MYR 150 per drawdown.', 3, 5, 'Underlying LC settled by CIMB. Goods identifiable and saleable. Trade finance facility limit approved.', ARRAY['octo_biz_current_myr','letter_of_credit'], 'Ahmad pays for wine import via LC, but needs 60 days to distribute and collect from local restaurants. Trust Receipt covers the gap.', 30, 180, ARRAY['MYR','USD','EUR'], FALSE, 'Goods remain constructively the bank''s until repayment. Sale proceeds to be deposited with CIMB. Subject to BNM trade finance guidelines.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('fd_myr', 'Fixed Deposit (MYR)', 'deposits', 'fd', 'Park idle MYR cash at a guaranteed rate for 30-365 days.', 'Standard MYR fixed deposit. Choose a tenor (30, 60, 90, 180, 365 days), lock in a rate, receive principal + interest on maturity. Tiered rates — higher amounts and longer tenors earn more. Auto-rollover available. Early withdrawal forfeits accrued interest. Suitable for SMEs with predictable surplus cash they don''t need for operations.', ARRAY['idle_cash_yield','short_term_parking'], '3.5% p.a. (30d), 3.8% p.a. (90d), 4.0% p.a. (180d), 4.2% p.a. (365d). Tiered uplift +0.1% for MYR 100K+ placements.', 1, 5, 'Any business entity. Minimum placement MYR 5,000. KYC documentation.', ARRAY[]::TEXT[], 'Surplus tax provision, set-aside dividend payments, end-of-quarter cash that won''t be needed for 90 days.', 30, 365, ARRAY['MYR'], FALSE, 'PIDM protected up to RM250,000 per depositor. Early withdrawal forfeits all accrued interest. Rates subject to change for new placements.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z'),
  ('foreign_currency_fd', 'Foreign Currency FD', 'deposits', 'foreign_currency_fd', 'Earn yield on foreign currency balances (EUR, AUD, USD) without converting to MYR.', 'Fixed deposit in foreign currency for SMEs who hold or expect to receive foreign currency. Locks in a yield while preserving FX exposure. Useful when an SME wants to hold a target currency buffer (e.g., EUR for monthly supplier payments) but still earn return on idle balances. Tenor 30-365 days. Settlement in the same currency.', ARRAY['fx_holding_yield','foreign_currency_smoothing','idle_cash_yield'], 'EUR: 0.5% p.a. (90d), 0.8% p.a. (365d). USD: 4.5% p.a. (90d), 4.8% p.a. (365d). AUD: 3.8% p.a. (90d), 4.0% p.a. (365d). Subject to market rate movements.', 2, 5, 'Multi-Currency Account holder. Minimum placement EUR 5,000 / USD 5,000 / AUD 5,000 equivalent.', ARRAY['multi_currency_account'], 'Hold a EUR buffer of EUR 20K to cover the next 2-3 months of supplier payments, while earning a small yield instead of holding idle. Used as part of the EUR Currency Account hedging strategy suggested in the v2 FX recommendation.', 30, 365, ARRAY['EUR','AUD','USD','GBP','SGD','JPY','CNY'], FALSE, 'FX risk borne by customer. PIDM protection does not apply to foreign currency deposits. Rates subject to market movements.', '2026-Q2', '2026-06-15T00:00:00Z', 'core_banking', 1, '2026-06-15T00:00:00Z', '2026-06-15T00:00:00Z');
INSERT INTO bank_product_pricing_daily (pricing_id, product_id, pricing_date, pricing_type, value_decimal, value_currency, tenor_label, min_threshold, max_threshold, customer_tier, effective_until, source, schema_version, created_at) VALUES
  ('price_0001', 'flexicash', '2026-06-08', 'interest_rate', 8.5, NULL, NULL, NULL, NULL, 'sme', '2026-06-09', 'treasury_rate_sheet', 1, '2026-06-08T06:00:00+08:00'),
  ('price_0002', 'working_capital_facility', '2026-06-08', 'interest_rate', 7.2, NULL, NULL, NULL, NULL, 'sme', '2026-06-09', 'treasury_rate_sheet', 1, '2026-06-08T06:00:00+08:00'),
  ('price_0003', 'trade_bridging_loan', '2026-06-08', 'interest_rate', 6.8, NULL, NULL, NULL, NULL, 'sme', '2026-06-09', 'treasury_rate_sheet', 1, '2026-06-08T06:00:00+08:00'),
  ('price_0004', 'sme_term_loan', '2026-06-08', 'interest_rate', 6.5, NULL, NULL, NULL, NULL, 'sme', '2026-06-09', 'treasury_rate_sheet', 1, '2026-06-08T06:00:00+08:00'),
  ('price_0005', 'business_credit_card', '2026-06-08', 'interest_rate', 18.0, NULL, NULL, NULL, NULL, 'sme', '2026-06-09', 'treasury_rate_sheet', 1, '2026-06-08T06:00:00+08:00'),
